9	      basePremium += SWORD_BASE_PREMIUM;
10	    }
11	  }
12	  const firstInsurance = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
13	  return basePremium + firstInsurance + PROCESSING_FEE;
14	}
